// jQuery for page scrolling feature - requires jQuery Easing plugin
$(function(){$(".page-scroll a").bind("click",function(d){var c=$(this);$("html, body").stop().animate({scrollTop:$(c.attr("href")).offset().top},1500,"easeInOutExpo");d.preventDefault()})});$(function(){$("body").on("input propertychange",".floating-label-form-group",function(b){$(this).toggleClass("floating-label-form-group-with-value",!!$(b.target).val())}).on("focus",".floating-label-form-group",function(){$(this).addClass("floating-label-form-group-with-focus")}).on("blur",".floating-label-form-group",function(){$(this).removeClass("floating-label-form-group-with-focus")})});$("body").scrollspy({target:".navbar-fixed-top"});$(".navbar-collapse ul li a").click(function(){$(".navbar-toggle:visible").click()});